//! Integration tests for typed unique-field references generated by `#[model]`.

use reinhardt_db::orm::expressions::FieldRef;
use reinhardt_db::orm::query::Filter;
use reinhardt_macros::model;
use serde::{Deserialize, Serialize};

#[derive(Serialize, Deserialize)]
#[model(
	app_label = "articles",
	table_name = "articles",
	constraints = [unique(fields = ["email"], name = "articles_email_unique")]
)]
struct Article {
	#[field(primary_key = true)]
	id: Option<i64>,

	#[field(max_length = 100, unique = true)]
	slug: Option<String>,

	#[field(max_length = 255)]
	email: String,

	#[field(max_length = 255)]
	title: String,
}

#[test]
fn model_generates_typed_accessors_for_unique_fields() {
	// Arrange
	let _: FieldRef<Article, Option<String>> = Article::field_slug();

	// Act
	let filter: Filter = Article::unique_slug().eq("typed-rpc".to_owned());

	// Assert
	assert_eq!(Article::unique_id().name(), "id");
	assert_eq!(Article::unique_slug().name(), "slug");
	assert_eq!(Article::unique_email().name(), "email");
	assert_eq!(filter.field, "slug");
}
